"""Unit tests for the OpenAPI schema generated by FastAPI.

No database required — these tests inspect the schema object only.
All paths checked here are required by docs/backend-api-contract.md.
"""

from __future__ import annotations

import pytest

from app.main import create_app


@pytest.fixture(scope="module")
def schema() -> dict:
    return create_app().openapi()


@pytest.fixture(scope="module")
def paths(schema) -> dict:
    return schema["paths"]


@pytest.fixture(scope="module")
def components(schema) -> dict:
    return schema.get("components", {}).get("schemas", {})


