def test_comment_request_schema_exists(components):
    assert "CommentRequest" in components


def test_comment_request_uses_text_not_comment(components):
    """Contract: body field is 'text'. Sending 'comment' must fail (extra=forbid)."""
    props = components["CommentRequest"].get("properties", {})
    assert "text" in props, "CommentRequest must have 'text' property"
    assert "comment" not in props, "CommentRequest must NOT have 'comment' property"


def test_comment_request_text_is_required(components):
    required = components["CommentRequest"].get("required", [])
    assert "text" in required


def test_comment_request_rejects_extra_fields(components):
    assert components["CommentRequest"].get("additionalProperties") is False


